### IndexedDB Batched Cursor Implementation (JavaScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs/slow-indexeddb.html

Demonstrates how to implement a batched cursor for efficient data retrieval from an IndexedDB store. It retrieves documents within a specified age range in batches, optimizing performance for large datasets. Dependencies include IndexedDB API.

```javascript
const maxAge = 25;
let result = [];
const tx = db.transaction([storeName], 'readonly', TRANSACTION_SETTINGS);
const store = tx.objectStore(storeName);
const index = store.index('age-index');
let lastDoc;
let done = false;

/**
 * Run the batched cursor until all results are retrieved
 * or the end of the index is reached.
 */
while (done === false) {
    await new Promise((res, rej) => {
        const range = IDBKeyRange.bound(
            /**
             * If we have a previous document as checkpoint, 
             * we have to continue from it's age and id values.
             */
            [
                lastDoc ? lastDoc.age : -Infinity,
                lastDoc ? lastDoc.id : -Infinity,
            ],
            [
                maxAge + 0.00000001,
                String.fromCharCode(65535)
            ],
            true,
            false
        );
        const openCursorRequest = index.getAll(range, batchSize);
        openCursorRequest.onerror = err => rej(err);
        openCursorRequest.onsuccess = e => {
            const subResult = e.target.result;
            lastDoc = lastOfArray(subResult);
            if (subResult.length === 0) {
                done = true;
            } else {
                result = result.concat(subResult);
            }
            res();
        };
    });
}
console.dir(result);
```

